example_2_type_validation.command:
db.createCollection('students', {
  validator: {
    bsonType: 'object',
    properties: {
      studentId: { bsonType: 'string' },
      age: { bsonType: 'int' },
      gpa: { bsonType: 'double' },
      isInternational: { bsonType: 'bool' }
    }
  }
})

example_3_range_validation.command:
db.createCollection('students', {
  validator: {
    bsonType: 'object',
    properties: {
      age: {
        bsonType: 'int',
        minimum: 16,
        maximum: 80,
        description: 'Age must be 16-80'
      },
      gpa: {
        bsonType: 'double',
        minimum: 0.0,
        maximum: 4.0,
        description: 'GPA must be 0.0-4.0'
      }
    }
  }
})

example_4_string_pattern.command:
db.createCollection('students', {
  validator: {
    bsonType: 'object',
    properties: {
      studentId: {
        bsonType: 'string',
        pattern: '^20260[0-9]{3}$',
        description: 'Student ID format: 202600001-20260060'
      },
      major: {
        bsonType: 'string',
        enum: ['Data Science', 'Computer Science', 'Engineering', 'Business'],
        description: 'Only allowed majors'
      }
    }
  }
})

example_5_nested_object_validation.command:
db.createCollection('students', {
  validator: {
    bsonType: 'object',
    properties: {
      name: {
        bsonType: 'object',
        required: ['first', 'last'],
        properties: {
          first: { bsonType: 'string', minLength: 1 },
          last: { bsonType: 'string', minLength: 1 }
        }
      },
      scholarshipDetails: {
        bsonType: 'object',
        properties: {
          amount: { bsonType: 'int', minimum: 0 },
          awarded: { bsonType: 'bool' }
        }
      }
    }
  }
})

example_6_array_validation.command:
db.createCollection('students', {
  validator: {
    bsonType: 'object',
    properties: {
      skills: {
        bsonType: 'array',
        minItems: 1,
        maxItems: 10,
        items: { bsonType: 'string' },
        description: 'Array of 1-10 skill strings'
      },
      courses: {
        bsonType: 'array',
        items: { bsonType: 'string' }
      }
    }
  }
})

section_5_real_world_student_example.create_command:
db.createCollection('students', {
  validationAction: 'error',
  validator: {
    $jsonSchema: {
      bsonType: 'object',
      required: ['studentId', 'name', 'age', 'major', 'gpa'],
      properties: {
        studentId: { bsonType: 'string', pattern: '^20260[0-9]{3}$' },
        name: {
          bsonType: 'object',
          required: ['first', 'last'],
          properties: {
            first: { bsonType: 'string', minLength: 1, maxLength: 50 },
            last: { bsonType: 'string', minLength: 1, maxLength: 50 }
          }
        },
        age: { bsonType: 'int', minimum: 16, maximum: 80 },
        major: { bsonType: 'string', minLength: 5 },
        gpa: { bsonType: 'double', minimum: 0.0, maximum: 4.0 },
        isInternational: { bsonType: 'bool' },
        enrollmentDate: { bsonType: 'date' },
        skills: { bsonType: 'array', minItems: 0, maxItems: 20, items: { bsonType: 'string' } },
        courses: { bsonType: 'array', items: { bsonType: 'string' } },
        scholarshipDetails: {
          bsonType: 'object',
          properties: {
            amount: { bsonType: 'int', minimum: 0 },
            awarded: { bsonType: 'bool' },
            notes: { bsonType: 'string' }
          }
        }
      }
    }
  }
})
